const CATALOG = [
  { sku: 'RUN-FAST-900-BLK', name: 'RunFast 900', color: 'black', sizes: [7,7.5,8,8.5,9,9.5,10,10.5,11,12], price_usd: 129, qty: 8 },
  { sku: 'RUN-FAST-900-WHT', name: 'RunFast 900', color: 'white', sizes: [6,7,8,9,10,11,12], price_usd: 129, qty: 4 },
  { sku: 'CITY-WALK-2-BLK', name: 'CityWalk 2', color: 'black', sizes: [6,7,8,9,10,11], price_usd: 109, qty: 5 },
  { sku: 'TRAIL-X-GRY', name: 'TrailX Pro', color: 'grey', sizes: [8,9,10,11,12,13], price_usd: 149, qty: 3 },
  { sku: 'SLIP-ON-NVY', name: 'EasySlip', color: 'navy', sizes: [6,7,8,9,10], price_usd: 89, qty: 6 },
];

const body = $input.first().json.body || $input.first().json;
const sizeStr = (body.size || '9').toString().replace(',', '.');
const size = parseFloat(sizeStr);
const colorReq = (body.color || '').toLowerCase().trim();

let matches = CATALOG.filter(i => i.sizes.includes(size));
if (colorReq) {
  const exact = matches.filter(i => i.color.includes(colorReq) || colorReq.includes(i.color));
  if (exact.length) matches = exact;
}

const items = matches.slice(0, 3).map(i => ({
  sku: i.sku,
  name: i.name,
  size: size,
  color: i.color,
  price_usd: i.price_usd,
  in_stock: i.qty > 0,
  quantity_available: i.qty,
}));

const alternatives = items.length === 0
  ? CATALOG
      .filter(i => Math.abs(i.sizes[Math.floor(i.sizes.length / 2)] - size) <= 1)
      .slice(0, 2)
      .map(i => ({ sku: i.sku, name: i.name, color: i.color, price_usd: i.price_usd, note: 'closest available size' }))
  : [];

return [{ json: { available: items.length > 0, items, alternatives, requested_size: size, requested_color: colorReq } }];

const body = $input.first().json.body || $input.first().json;

const now = new Date();
const datePart = now.toISOString().slice(0, 10).replace(/-/g, '');
const rand = Math.random().toString(36).substring(2, 8).toUpperCase();
const orderId = `SHOE-${datePart}-${rand}`;

const readyDate = new Date(now);
readyDate.setDate(readyDate.getDate() + 1);
const readyStr = readyDate.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

const VALID_SKUS = ['RUN-FAST-900-BLK','RUN-FAST-900-WHT','CITY-WALK-2-BLK','TRAIL-X-GRY','SLIP-ON-NVY'];
const sku = body.sku || '';

return [{ json: {
  created: true,
  order_id: orderId,
  status: 'confirmed',
  sku: sku,
  sku_valid: VALID_SKUS.includes(sku),
  size: body.size || '',
  color: body.color || '',
  quantity: body.quantity || 1,
  customer_name: body.customer_name || '',
  payment_method: body.payment_method || 'pay-in-store',
  estimated_ready: readyStr,
  created_at: now.toISOString(),
}}];

const body = $input.first().json.body || $input.first().json;

const STORES = ['Downtown', 'Eastside Mall', 'Westpark Center'];
const locationReq = (body.store_location || 'Downtown').toLowerCase();
const resolvedStore = STORES.find(s => s.toLowerCase().includes(locationReq) || locationReq.includes(s.toLowerCase().split(' ')[0])) || 'Downtown';

const slots = [];
for (let d = 1; d <= 4; d++) {
  const dt = new Date();
  dt.setDate(dt.getDate() + d);
  if (dt.getDay() === 0) continue;
  const label = dt.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });
  slots.push({ day: label, window: '10 AM to 1 PM', slot_id: `PKP-${d}A` });
  slots.push({ day: label, window: '3 PM to 6 PM', slot_id: `PKP-${d}B` });
  if (slots.length >= 6) break;
}

const preferred = (body.pickup_window || '').toLowerCase();
const now = new Date();
const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

function isPastPickupRequest(text) {
  if (!text) return false;
  if (/(yesterday|last week|last monday|last tuesday|last wednesday|last thursday|last friday|last saturday|last sunday)/.test(text)) {
    return true;
  }

  const isoMatch = text.match(/\b(\d{4})-(\d{2})-(\d{2})\b/);
  if (isoMatch) {
    const requested = new Date(Number(isoMatch[1]), Number(isoMatch[2]) - 1, Number(isoMatch[3]));
    if (requested < today) return true;
  }

  const monthMatch = text.match(/\b(january|february|march|april|may|june|july|august|september|october|november|december)\s+(\d{1,2})\b/);
  if (monthMatch) {
    const requested = new Date(`${monthMatch[1]} ${monthMatch[2]}, ${now.getFullYear()}`);
    if (!Number.isNaN(requested.getTime()) && requested < today) return true;
  }

  const timeMatch = text.includes('today') ? text.match(/\b(1[0-2]|0?[1-9])(?::([0-5]\d))?\s*(am|pm)\b/) : null;
  if (timeMatch) {
    let hour = Number(timeMatch[1]) % 12;
    const minute = Number(timeMatch[2] || 0);
    if (timeMatch[3] === 'pm') hour += 12;
    const requested = new Date(now.getFullYear(), now.getMonth(), now.getDate(), hour, minute);
    if (requested < now) return true;
  }

  return false;
}

const matched = slots.find(s =>
  preferred && (preferred.includes(s.window.toLowerCase()) || preferred.includes(s.day.toLowerCase().split(',')[0]))
) || slots[0];

if (isPastPickupRequest(preferred)) {
  return [{ json: {
    success: false,
    booked: false,
    reason: 'Requested pickup time is in the past.',
    order_id: body.order_id || '',
    store_location: resolvedStore,
    available_slots: slots.slice(0, 4),
  }}];
}

const confCode = 'PU-' + Math.random().toString(36).substring(2, 8).toUpperCase();

return [{ json: {
  booked: true,
  order_id: body.order_id || '',
  store_location: resolvedStore,
  pickup_window: `${matched.day}, ${matched.window}`,
  slot_id: matched.slot_id,
  confirmation_code: confCode,
  available_slots: slots.slice(0, 4),
}}];
